CREATE TABLE PRISON_LEAVERS_JOB (JOB_ID BIGINT NOT NULL, MN_JOB_ID BIGINT NOT NULL, SALARY_PERIOD_ID BIGINT NOT NULL, WORK_PATTERN_ID BIGINT NOT NULL, HOURS_TYPE_ID BIGINT NOT NULL, JOB_CONTRACT_TYPE_ID BIGINT NOT NULL, JOB_TYPE_ID BIGINT NOT NULL, BASE_LOCATION_ID BIGINT NOT NULL, JOB_CONTRACT_ID BIGINT NOT NULL, EMPLOYER_ID BIGINT NOT NULL, EMPLOYER_SECTOR_ID BIGINT NOT NULL, ADDITIONAL_SALARY_INFORMATION CHARACTER VARYING(255), DESIRABLE_JOB_CRITERIA CHARACTER VARYING(255), ESSENTIAL_JOB_CRITERIA CHARACTER VARYING(255), CLOSING_DATE TIMESTAMP(6) WITHOUT TIME ZONE, HOW_TO_APPLY CHARACTER VARYING(255), JOB_TITLE CHARACTER VARYING(255), MN_CREATED_BY_ID BIGINT NOT NULL, CREATED_BY CHARACTER VARYING(255), CREATED_DATE_TIME TIMESTAMP(6) WITHOUT TIME ZONE, POSTING_DATE CHARACTER VARYING(255), MN_DELETED_BY_ID BIGINT NOT NULL, DELETED_BY CHARACTER VARYING(255), DELETED_DATE_TIME TIMESTAMP(6) WITHOUT TIME ZONE, MODIFIED_BY CHARACTER VARYING(255), MODIFIED_DATE_TIME TIMESTAMP(6) WITHOUT TIME ZONE, NATIONAL_MINIMUM_WAGE BOOLEAN, POST_CODE CHARACTER VARYING(255), RING_FENCED_JOB BOOLEAN, ROLLING_JOB_OPPURTUNITY BOOLEAN, ACTIVE_JOB BOOLEAN, DELETED_JOB BOOLEAN, SALARY_FROM CHARACTER VARYING(255), SALARY_TO CHARACTER VARYING(255), TYPE_OF_WORK CHARACTER VARYING(255), PRIMARY KEY (JOB_ID));
CREATE TABLE PRISON_LEAVERS_PROFILE (PRISON_LEAVER_ID  VARCHAR(7) PRIMARY KEY   NOT NULL, CREATED_BY VARCHAR(255), CREATED_DATE_TIME TIMESTAMP(6) WITHOUT TIME ZONE, MODIFIED_BY VARCHAR(255), MODIFIED_DATE_TIME TIMESTAMP(6) WITHOUT TIME ZONE);
CREATE TABLE prison_leaver_job_intrest_table (PRISON_LEAVER_ID VARCHAR(7) NOT NULL, PRISON_LEAVERS_JOB_ID BIGINT NOT NULL, PRIMARY KEY (PRISON_LEAVER_ID, PRISON_LEAVERS_JOB_ID));
CREATE TABLE PRISON_LEAVERS_JOB (JOB_ID BIGINT NOT NULL, ACTIVE_JOB BOOLEAN, ADDITIONAL_SALARY_INFORMATION VARCHAR(255), CLOSING_DATE TIMESTAMP(6), CREATED_BY VARCHAR(255), CREATED_DATE_TIME TIMESTAMP(6) WITH TIME ZONE, DELETED_BY VARCHAR(255), DELETED_DATE_TIME TIMESTAMP(6) WITH TIME ZONE, DELETED_JOB BOOLEAN, DESIRABLE_JOB_CRITERIA VARCHAR(255), ESSENTIAL_JOB_CRITERIA VARCHAR(255), HOURS_NAME VARCHAR(255), HOW_TO_APPLY VARCHAR(255), JOB_CONTRACT_ID BIGINT , JOB_CONTRACT_NAME VARCHAR(255) , JOB_TITLE VARCHAR(255), JOB_TYPE_NAME VARCHAR(255) , SECTOR_NAME VARCHAR(255) , MODIFIED_BY VARCHAR(255), MODIFIED_DATE_TIME TIMESTAMP(6) WITH TIME ZONE, NATIONAL_MINIMUM_WAGE BOOLEAN, POST_CODE VARCHAR(255), POSTING_DATE VARCHAR(255), RING_FENCED_JOB BOOLEAN, ROLLING_JOB_OPPURTUNITY BOOLEAN, SALARY_FROM VARCHAR(255), SALARY_PERIOD_NAME VARCHAR(255), SALARY_TO VARCHAR(255), TYPE_OF_WORK VARCHAR(255), WORK_PATTERN_NAME VARCHAR(255), EMPLOYER_ID BIGINT NOT NULL, PRIMARY KEY (JOB_ID));
CREATE TABLE SIMPLE_JOB_EMPLOYERS (EMPLOYER_ID BIGINT NOT NULL, CREATED_BY VARCHAR(255), CREATED_DATE_TIME TIMESTAMP(6), EMPLOYER_BIO VARCHAR(255), EMPLOYER_NAME VARCHAR(255), GRADE VARCHAR(255) , IMAGE_PATH VARCHAR(255) , MODIFIED_BY VARCHAR(255), MODIFIED_DATE_TIME TIMESTAMP(6), PARTNER_NAME VARCHAR(255) , POST_CODE VARCHAR(8), SECTOR_NAME VARCHAR(255) , PRIMARY KEY (EMPLOYER_ID));
ALTER TABLE IF EXISTS prison_leaver_job_intrest_table ADD CONSTRAINT FK_prison_leaver_job_intrest_table_PRISON_LEAVERS_JOB FOREIGN KEY (PRISON_LEAVERS_JOB_ID) REFERENCES SIMPLE_PRISON_LEAVERS_JOB ON DELETE CASCADE;
ALTER TABLE IF EXISTS prison_leaver_job_intrest_table ADD CONSTRAINT FK_PRISON_LEAVERS_JOB_PRISON_LEAVERS_PROFILE FOREIGN KEY (PRISON_LEAVER_ID) REFERENCES PRISON_LEAVERS_PROFILE ON DELETE CASCADE;
ALTER TABLE IF EXISTS PRISON_LEAVERS_JOB ADD CONSTRAINT FK_PRISON_LEAVERS_JOB_SIMPLE_JOB_EMPLOYERS FOREIGN KEY (EMPLOYER_ID) REFERENCES SIMPLE_JOB_EMPLOYERS  ON DELETE CASCADE;

CREATE SEQUENCE IF NOT EXISTS SIMPLE_PRISON_LEAVERS_JOB_SEQ START WITH 1 INCREMENT BY 50;
CREATE SEQUENCE IF NOT EXISTS SIMPLE_JOB_EMPLOYERS_SEQ START WITH 1 INCREMENT BY 50;
CREATE SEQUENCE IF NOT EXISTS HIBERNATE_SEQ START WITH 1 INCREMENT BY 50;
CREATE SEQUENCE IF NOT EXISTS PRISON_LEAVERS_JOB_SEQ START WITH 1 INCREMENT BY 50;
